@Test
	public void getBodyIterator() {
		Iterator<Body> it = aj.getBodyIterator();
		TestCase.assertNotNull(it);

		Body b1 = null;
		Body b2 = null;


		int n = 0;
		while (it.hasNext()) {
			if (n == 0) b1 = it.next();
			if (n == 1) b2 = it.next();
			n++;
		}

		TestCase.assertEquals(2, n);
		TestCase.assertEquals(this.b1, b1);
		TestCase.assertEquals(this.b2, b2);
	}
